from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)

# Replace with your own Infura project ID
INFURA_PROJECT_ID = 'your_infura_project_id'
WEB3_INFURA_URL = f'https://mainnet.infura.io/v3/{INFURA_PROJECT_ID}'
web3 = Web3(Web3.HTTPProvider(WEB3_INFURA_URL))

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    
    if not data or 'message' not in data or 'signature' not in data:
        return jsonify({'error': 'Missing message or signature'}), 400
    
    message = data['message']
    signature = data['signature']
    
    try:
        # Recover the address from the signature
        recovered_address = web3.eth.account.recover_message(message, signature=signature)
        
        if not recovered_address:
            return jsonify({'error': 'Invalid signature'}), 401
        
        # Check if the recovered address is allowed (use an allowlist for security)
        allowed_addresses = ['0xYourAllowedAddress']
        if recovered_address.lower() not in [addr.lower() for addr in allowed_addresses]:
            return jsonify({'error': 'Unauthorized address'}), 403
        
        return jsonify({'message': 'Signature verified successfully', 'address': recovered_address}), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)